import React from "react";
import "./Dashboard.css";
import Sidebar from "../../components/Sidebar/Sidebar";
import StatCard from "../../components/StatCard/StatCard";
import DriverList from "../../components/DriverList/DriverList";
import ClientList from "../../components/ClientList/ClientList";

function Dashboard({ onLogout }) {
  // The 4 summary numbers at the top. Keeping them as data (instead of
  // 4 hand-written <StatCard /> tags) makes it trivial to add a 5th one later.
  const stats = [
    { label: "Total Call", value: "1,245", icon: "📞" },
    { label: "Total Rems", value: "970", icon: "🎖" },
    { label: "Total RPM", value: "2.5M", icon: "📈" },
    { label: "Total PRI", value: "450", icon: "✏️" },
  ];

  return (
    <div className="dashboard-layout">
      <Sidebar activeItem="overview" onLogout={onLogout} />

      <main className="dashboard-main">
        <header className="dashboard-topbar">
          <h1>Dashboard Overview</h1>
          <div className="topbar-actions">
            <button className="btn btn-outline">+ Add Client</button>
            <button className="btn btn-primary">+ Add Driver</button>
          </div>
        </header>

        <section className="stat-grid">
          {stats.map((stat) => (
            <StatCard
              key={stat.label}
              label={stat.label}
              value={stat.value}
              icon={stat.icon}
            />
          ))}
        </section>

        <section className="lists-grid">
          <DriverList />
          <ClientList />
        </section>
      </main>
    </div>
  );
}

export default Dashboard;
